+impl std::fmt::Display for StreamingConsumerDisconnected {
+    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
+        write!(
+            f,
+            "streaming consumer disconnected while sending batch for {}",
+            self.connector_name
+        )
+    }
